// public/data/questions.json, which makes the generator trivial.
//
// IMPORTANT: These are NOT real exam questions. They are practice items
// derived from general subject knowledge. They are tagged
// `source: 'generated'` in the output and the UI surfaces this clearly.
//
// Adding to this file: just push more facts to the array for a subject.
// The generator will produce as many question variations as needed by
// re-using facts with different phrasings (prefix/suffix templates).

/** @typedef {{ prompt: string, options: string[], correct: number, explanation: string, topic: string, variants?: string[] }} Fact */

/** @param {string} correctAnswer @param {string} topic */
function makeExplanation(correctAnswer, topic) {
  return `The correct answer is "${correctAnswer}". This is a fundamental concept in ${topic.toLowerCase()}.`;
}

